const XLSX = require\('xlsx'\);
const wb = XLSX.readFile\('APIS 배합툴설계-크로스폴리머2 \(1\).xlsx'\);
console.log\('Sheets:', wb.SheetNames\);
wb.SheetNames.forEach\(name => {
  console.log\('\\n=== Sheet:', name, '==='\);
  const ws = wb.Sheets[name];
  const range = XLSX.utils.decode_range\(ws['!ref'] || 'A1'\);
  console.log\('Range:', ws['!ref']\);

  // Print merged cells
  if\(ws['!merges']\) {
    console.log\('Merged cells:', ws['!merges'].map\(m => XLSX.utils.encode_range\(m\)\).join\(', '\)\);
  }

  // Print all cells with values
  for\(let r = range.s.r; r <= range.e.r; r++\) {
    let rowVals = [];
    for\(let c = range.s.c; c <= range.e.c; c++\) {
      const addr = XLSX.utils.encode_cell\({r, c}\);
      const cell = ws[addr];
      if\(cell && cell.v !== undefined && cell.v !== null\) {
        rowVals.push\(addr + '=' + JSON.stringify\(cell.v\)\);
      }
    }
    if\(rowVals.length\) console.log\('Row', r+1, ':', rowVals.join\(' | '\)\);
  }
}\);
